INSERT INTO public.photos VALUES (25093, 'El Baulero 1936', 'El Baulero, apodo de Pedro Dâ”œÂ¡az Layâ”œâ•‘s (Zaragoza, 1907-1972), tenâ”œÂ¡a un taller de baâ”œâ•‘les en la calle de Las Armas, y â”œÂ®l mismo los transportaba: en bicicleta. Hijo de torero, decidiâ”œâ”‚ probar suerte como rejoneador: en bicicleta, debutando en la plaza de Toros de Zaragoza el 18 de julio de 1936. Despuâ”œÂ®s se dedicâ”œâ”‚ a torear coches: en bicicleta. Muriâ”œâ”‚ atropellado en la calle del General Franco: caminando. Fuente: Heraldo de Aragâ”œâ”‚n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65453400, -0.89161300, '0101000020E6100000C40776FC1788ECBF5E0F26C5C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32727769115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32727769115.webp', 'https://www.flickr.com/photos/zaragozaantigua/32727769115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25595, 'Oeste de la Romareda 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Abril 1973. Imagen ligeramente en altura, desde uno de los nuevos grandes bloques de viviendas de la calle Condes de Aragâ”œâ”‚n, del panorama al oeste del nuevo Polâ”œÂ¡gono Romareda, hasta el Seminario Conciliar. Junto a las nuevos y modernos viales y edificios habitacionales, conviven aâ”œâ•‘n islotes verdes con campos de cultivos de herbâ”œÃ­ceas y cereales. Por uno de los caminos entre esos campos estuvo trazado el recorrido del antiguo ferrocarril de Cariâ”œâ–’ena.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63914000, -0.90647300, '0101000020E6100000CF9F36AAD301EDBF60C8EA56CFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14715394467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14715394467.webp', 'https://www.flickr.com/photos/zaragozaantigua/14715394467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20949, 'Puerta de Santa Engracia 1828', 'Josâ”œÂ® Gabriel Lafuente (1828) Puerta de Santa Engracia. Tiburcio del Caso diseâ”œâ–’â”œâ”‚ una nueva puerta de Santa Engracia ubicada a la altura de las ruinas del convento jeronimiano de Santa Engracia y la Torre del Pino, en el vial abierto tras la guerra de 1808-1813 entre el Coso y Santa Engracia. Era una puerta en forma de arco de triunfo que recordara los Sitios, y este proyecto (porque hubo varios) se quiso acometer antes de la visita del monarca absoluto Fernando VII "El Deseado", el 22 de abril de 1828. Como no se planificaron las cosas bien, se ordenâ”œâ”‚ levantar interinamente una imitaciâ”œâ”‚n de madera, lienzo y pintura denominada "Puerta Ynterina", que lo fue hasta 1830, en que se colocâ”œâ”‚ la primera piedra...', 1828, 1828, 1828, 'Siglo XIX', 'CENTRO', 41.64957900, -0.88371200, '0101000020E6100000E8A562635E47ECBF8E95986725D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15090162539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15090162539.webp', 'https://www.flickr.com/photos/zaragozaantigua/15090162539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20951, 'Puerta de Santa Engracia 1830', '"Segunda Puerta de Santa Engracia", Antonio Callaved, 2011. Este arco conmemorativo quiso estar erguido en el actual paseo de la Independencia entre 1830 y 1866, aunque sâ”œâ”‚lo lo consiguiâ”œâ”‚ siendo de madera policromada. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1830, 1830, 1830, 'Siglo XIX', 'CENTRO', 41.64944200, -0.88369000, '0101000020E6100000F3AB39403047ECBF0D535BEA20D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093334339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093334339.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093334339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20980, 'Paseo de Santa Engracia 1833', '"Dibujo que representa las fachadas de los edificios que deben executar los que hayan de reedificar sus casas en la distancia que media entre la plaza de San Fernando y la Puerta de Santa Engracia que se estâ”œÃ­ construyendo", 1833. Dibujo que contiene tres figuras: dos alzados correspondientes a las esquinas con la plaza de San Fernando (hoy de Espaâ”œâ–’a) y la Puerta de Santa Engracia (hoy plaza de Aragâ”œâ”‚n), y una planta de los mismos emplazamientos. Este paseo se llamarâ”œÃ­ de Santa Engracia, luego Salâ”œâ”‚n de Pignatelli y hoy de la Independencia. Fuente: AMZ.', 1833, 1833, 1833, 'Siglo XIX', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20870392918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20870392918.webp', 'https://www.flickr.com/photos/zaragozaantigua/20870392918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21037, 'Cabalgata 1860', 'Dibujo ilustrativo de la cabalgata que en octubre de 1860 recreâ”œâ”‚ de forma libre la coronaciâ”œâ”‚n de Fernando de Antequera como rey de Aragâ”œâ”‚n tras el Compromiso de Caspe de 1412. Este evento estuvo incluido en el programa de actos organizado con motivo de la visita a la ciudad de la reina Isabel II, el rey consorte Francisco de Asâ”œÂ¡s, los infantes y el heredero al trono, futuro Alfonso XII. Enanos y Gigantones, ademâ”œÃ­s de carros alegâ”œâ”‚ricos decorados con diversos motivos acompaâ”œâ–’aron a la cabalgata en su recorrido desde la Real Casa de Misericordia hasta el Palacio Arzobispal en funciones de Palacio Real, incluyendo algunos giros hasta la plaza de la Magdalena y la del Mercado, para regresar finalmente al lugar de salida. En el dibujo, la recreacionista cabalgata avanza por el Salâ”œâ”‚n de Pignatelli, decorado con vegetales arcos y banderolas al viento. Fuente visual: revista El Museo Universal (Madrid, 25/11/1860).', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64974900, -0.88322800, '0101000020E6100000E92ADD5D6743ECBFEACDA8F92AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35609880824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35609880824.webp', 'https://www.flickr.com/photos/zaragozaantigua/35609880824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21134, 'Calle de la Independencia c.1880', 'Imagen coloreada con una insâ”œâ”‚lita y simpâ”œÃ­tica vista del â”œâ•‘ltimo tramo de los nâ”œâ•‘meros pares de la calle de la Independencia, centrada en el solar ocupado en el centro de la escena por los Baâ”œâ–’os de Fermâ”œÂ¡n Zacarâ”œÂ¡as â”œÃ¬â”œâ–’igo, en cuya esquina recayente con la calle del Azoque (tramo luego redenominado del Marquâ”œÂ®s de Casa Jimâ”œÂ®nez) y desde 1864 estaba ubicado el Teatro de Novedades, clausurado en 1892 para dar paso a los inmuebles que poco despuâ”œÂ®s se construirâ”œÂ¡an allâ”œÂ¡ y completarâ”œÂ¡an la visual de los porches a la parisina forma que singularizan este espacio. A la izquierda, el original inmueble conocido como Ambos Mundos por albergar ese homâ”œâ”‚nimo y prestigioso gran cafâ”œÂ®. Al fondo, la plaza de la Constituciâ”œâ”‚n', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64973900, -0.88374400, '0101000020E6100000BF28417FA147ECBFC6F7C5A52AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49896759551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49896759551.webp', 'https://www.flickr.com/photos/zaragozaantigua/49896759551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21204, 'Cafâ”œÂ® Ambos Mundos c.1890', 'Imagen del interior del cafâ”œÂ® Ambos Mundos con el aspecto conferido por la reforma que en 1889 y con proyecto del arquitecto Julio Bravo le dio este apabullante aspecto decorativo en "estilo renacimiento".', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64939400, -0.88427000, '0101000020E610000079AF5A99F04BECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54394831882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54394831882.webp', 'https://www.flickr.com/photos/zaragozaantigua/54394831882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21307, 'Calle de la Independencia c.1906', 'Festiva imagen capturada en el andador central de la calle de la Independencia, mientras la comparsa de cabezudos encorre a la chiquillerâ”œÂ¡a en direcciâ”œâ”‚n a la plaza de la Constituciâ”œâ”‚n, a la altura de los antiguos nâ”œâ•‘meros del 15, 17 y 19, este â”œâ•‘ltimo correspondiente con el convento de las Religiosas de Jerusalâ”œÂ®n, a la derecha. Centra la escena el cabezudo que representa al Tuerto metido en faena. Fuente visual: imagen estereoscâ”œâ”‚pica reproducida en El Periâ”œâ”‚dico de Aragâ”œâ”‚n. En GAZA ofrecemos una composiciâ”œâ”‚n basada en ella.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.65083600, -0.88196400, '0101000020E6100000A0FA07910C39ECBF9C8713984ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34975554010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34975554010.webp', 'https://www.flickr.com/photos/zaragozaantigua/34975554010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21365, 'P.â”¬â•‘ de la Independencia 1913', 'Acto castrense en el paseo: "Jura de banderas", el 13 de abril de 1913. A la derecha, el palacete del barâ”œâ”‚n de la Rosa (nâ”¬â•‘ 29), que fuera sede de la Capitanâ”œÂ¡a General entre 1867 y 1888, y casa de Luis Buâ”œâ–’uel entre 1906 y 1917, antes de ser derribado en 1927 para levantar el nuevo edificio del Heraldo de Aragâ”œâ”‚n, y el de Escoriaza. Al otro lado de la plaza de Santa Engracia, los porches del paseo ya terminados, con pâ”œâ•‘blico encaramado, pero sin el edificio de Correos.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64970500, -0.88318000, '0101000020E6100000A5660FB40243ECBF1A868F8829D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920637137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920637137.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920637137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21390, 'P.â”¬â•‘ de la Independencia 1913', 'Paseo de la Independencia de Zaragoza el 19 de marzo de 1913, con visual de los edificios de la acera de los impares. Junto a la plaza de Santa Engracia, el palacio del conde de la Rosa. Al fondo, el quiosco de la mâ”œâ•‘sica. Foto: Lorenzo Almarza. Fuente visual: Archivo de la Diputaciâ”œâ”‚n Provincial de Huesca www.dphuesca.es/', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20742624271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20742624271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20742624271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21396, 'P.â”¬â•‘ de la Independencia 1913', 'Foto: Lorenzo Almarza. "Jura de banderas. El beso". Fotografâ”œÂ¡a de detalle del paseo de la Independencia de Zaragoza el 13 de abril de 1913, con un quiosco en primer plano y vista parcial del teatro Pignatelli, que serâ”œÃ­ cerrado tras las fiestas del Pilar de 1914. En parte de su solar se inaugurarâ”œÃ­ el edificio de Correos en 1926. Fuente visual: Archivo Diputaciâ”œâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64947300, -0.88373500, '0101000020E6100000F3936A9F8E47ECBF485167EE21D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21469490155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21469490155.webp', 'https://www.flickr.com/photos/zaragozaantigua/21469490155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21398, 'P.â”¬â•‘ de la Independencia 1913', 'Foto: Lorenzo Almarza. Desfile militar en el paseo de la Independencia de Zaragoza en 1913. Al fondo, una torreta de la Facultad de Medicina y Ciencias. Hemos volteado horizontalmente la imagen para darle sentido. Fuente: Archivo de la Diputaciâ”œâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21471724675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21471724675.webp', 'https://www.flickr.com/photos/zaragozaantigua/21471724675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21424, 'Calle de la Independencia 1911', 'Esta captura es titulada "Jura de bandera de los artilleros en la plaza Aragâ”œâ”‚n de Zaragoza", aunque nos parece que dicha plaza queda mâ”œÃ­s al sur (hacia la derecha de la imagen), y el evento estâ”œÃ­ sucediendo en el andador central de la calle de la Independencia, a la altura del emboque a la de Felipe Sanclemente, que continâ”œâ•‘a hacia el fondo, y nos ofrece una insâ”œâ”‚lita visual del nâ”¬â•‘ 2 de esa calle. En primer plano, vista parcial del nâ”¬â•‘ 25 de Independencia, en cuyos bajos se ubicaba el Cafâ”œÂ® de la Iberia, y del esquinero nâ”¬â•‘ 27, ambos de alturas bastante provincianas. Confronta, al otro lado de la calle, el entraâ”œâ–’able edificio-manzana (pequeâ”œâ–’a) delimitado por las calles de Felipe Sanclemente, Santa Engracia, Garcâ”œÂ¡a Gil, y la propia de Independencia. Fuente visual: Luis Gandâ”œâ•‘ Mercadal, patrimoniocultural.unizar.es/', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65002300, -0.88296300, '0101000020E61000005F7F129F3B41ECBFEB5223F433D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32206536506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32206536506.webp', 'https://www.flickr.com/photos/zaragozaantigua/32206536506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21435, 'Teatro Circo 1911', 'Foto: Grasa. Posado del personal sanitario del hospital de sangre instalado en el cafâ”œÂ® del Teatro Circo de la calle de San Miguel, durante la huelga general revolucionaria del verano-otoâ”œâ–’o de 1911. Fuente: Diario ABC, 22-9-1911.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65079900, -0.88038500, '0101000020E61000005C72DC291D2CECBF7FA2B2614DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40166094270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40166094270.webp', 'https://www.flickr.com/photos/zaragozaantigua/40166094270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21440, 'P.â”¬â•‘ de la Independencia 1913', 'Luminosa imagen capturada en el paseo de la Independencia y centrada en la ubicaciâ”œâ”‚n del bulevar central donde poco antes (1912) habâ”œÂ¡a sido instalado el Quiosco de la Mâ”œâ•‘sica, ideado originalmente por los hermanos Martâ”œÂ¡nez Ubago para la Exposiciâ”œâ”‚n Hispano Francesa de 1908. Aquâ”œÂ¡ estarâ”œÂ¡a hasta que en 1927 fue recolocado en el antiguo recinto expositivo, ya urbanizado como plaza de Castelar. Al fondo y a la izquierda, la calle de Jerâ”œâ”‚nimo Zurita, y a continuaciâ”œâ”‚n el antiguo inmueble de los nâ”œâ•‘meros 23-25 del paseo. En los bajos del nâ”¬â•‘ 25, a la derecha, destaca el ingreso al Cafâ”œÂ® de la Iberia en su segunda â”œÂ®poca (desde 1893), considerado en su momento el segundo cafâ”œÂ® en tamaâ”œâ–’o de Zaragoza, tras el Ambos Mundos. Al inicio de la dâ”œÂ®cada de los aâ”œâ–’os 30 aquâ”œÂ¡ se ubicarâ”œÂ¡a el moderno Cafâ”œÂ®-Cervecerâ”œÂ¡a Baviera.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65037200, -0.88271400, '0101000020E61000004015376E313FECBFF71DC3633FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48568827556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48568827556.webp', 'https://www.flickr.com/photos/zaragozaantigua/48568827556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21443, 'P.â”¬â•‘ de la Independencia c.1918', 'Imagen capturada en el andador central del paseo de la Independencia durante una fresca maâ”œâ–’ana y centrada en el Quiosco de la Mâ”œâ•‘sica donde una orquesta toca mâ”œâ•‘sica, rodeado de numeroso pâ”œâ•‘blico. Por el paseo arriba, endomingadas seâ”œâ–’oras y seâ”œâ–’ores, y algunas amas de crâ”œÂ¡a. A la izquierda, la calle de Fray Diego Murillo se abre entre los inmuebles de los nâ”œâ•‘meros 14 y 16 del paseo, de los seâ”œâ–’ores Josâ”œÂ® Moncasi y Santiago Baselga, respectivamente. Al fondo, leve vista de la emergente torre de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65055700, -0.88262900, '0101000020E6100000B309302C7F3EECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49847053757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49847053757.webp', 'https://www.flickr.com/photos/zaragozaantigua/49847053757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21474, 'Cinema Alhambra 1911', 'Ubicado en el paseo de la Independencia 26, el Cinema Alhambra se inaugurâ”œâ”‚ el 6 de octubre de 1911. Construido segâ”œâ•‘n diseâ”œâ–’o del arquitecto Fâ”œÂ®lix Navarro, la obra fue terminada por su hijo Miguel â”œÃ¼ngel Navarro. Su decoraciâ”œâ”‚n interior era neonazarâ”œÂ¡. Fue clausurado en agosto de 1965. En su solar se levantâ”œâ”‚ el Cine Avenida en 1967.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65019900, -0.88332600, '0101000020E61000009D9B36E33444ECBF2A7288B839D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54394485322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54394485322.webp', 'https://www.flickr.com/photos/zaragozaantigua/54394485322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21483, 'P.â”¬â•‘ de la Independencia c.1926', 'El edificio situado en el paseo de la Independencia 29, conocido como Casa Pamplona, que habâ”œÂ¡a sido Capitanâ”œÂ¡a General, estuvo ocupado en parte por los Hermanos Corazonistas entre 1904 y 1910. Luis Buâ”œâ–’uel viviâ”œâ”‚ en este mismo edificio entre 1906 y 1917. Desde 1931, los nâ”œâ•‘meros 29 y 31 del paseo los ocupan el Heraldo de Aragâ”œâ”‚n y la casa de la familia Escoriaza, codo con codo y demolida ya la casa que nos ocupa. Al fondo, los nuevos edificios de Correos y telâ”œÂ®grafos y el mâ”œÃ­s nuevo y en obras de los telâ”œÂ®fonos. Fuente: Luis Buâ”œâ–’uel. La forja de un cineasta universal, 2013.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64962500, -0.88312300, '0101000020E6100000950D6B2A8B42ECBFFED478E926D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962269776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962269776.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962269776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22309, 'Tony Leblanc 1965', 'Visita a Zaragoza, acompaâ”œâ–’ando a la cantante folclâ”œâ”‚rica Lolita Sevilla, del humorista madrileâ”œâ–’o Tony Leblanc (1922-2012) (en el centro, en un salâ”œâ”‚n de la Residencia Sanitaria Josâ”œÂ® Antonio o Casa Grande). Nacido en el Museo del Prado de Madrid como Ignacio Fernâ”œÃ­ndez, participâ”œâ”‚ en pelâ”œÂ¡culas populares desplegando su indudable vis câ”œâ”‚mica. El momento cumbre de su carrera fue cuando se comiâ”œâ”‚ una manzana en directo en Televisiâ”œâ”‚n Espaâ”œâ–’ola, en 1977. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661700347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661700347.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661700347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21519, 'Casa Jimâ”œÂ®nez 1921', 'Una fotografâ”œÂ¡a casual de Rufina, en tono familiar, sin mâ”œÃ­s pretensiones que captar un instante relajado y domâ”œÂ®stico, con el inopinado fondo urbano del momento. El resultado es espectacular. El marco escâ”œÂ®nico es la calle de Casa Jimâ”œÂ®nez en su ligazâ”œâ”‚n con el tranquilo paseo de la Independencia. Al otro lado, la portada de la parroquia de Santa Engracia (remozada 30 aâ”œâ–’os antes por Mariano Lâ”œâ”‚pez), en una visual insâ”œâ”‚lita, pues el edificio de "Correos y Telâ”œÂ®grafos" no estâ”œÃ­, y apenas si despuntan los arquitrabados neo-porches que delimitan una parte del espacio que hasta hacâ”œÂ¡a unos pocos aâ”œâ–’os ocupaba el fungible Teatro Pignatelli. Ni siquiera el alto edificio de la derecha es el mismo: unos aâ”œâ–’os despuâ”œÂ®s, Pascual Bravo reformarâ”œÂ¡a profundamente este enorme receptâ”œÃ­culo, en sus bajos, del seâ”œâ–’alado y desaparecido cafâ”œÂ® "Ambos Mundos". Fuente visual: fotografâ”œÂ¡a de Julio Requejo, proporcionada amablemente por Mariano Lacruz.', 1921, 1921, 1921, 'Anos 20', 'CENTRO', 41.64988300, -0.88417400, '0101000020E6100000F226BF45274BECBFFA9CBB5D2FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16461101982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16461101982.webp', 'https://www.flickr.com/photos/zaragozaantigua/16461101982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21522, 'Calle de Câ”œÃ­diz 1923', 'Desde las traseras de su casa de la calle Casa Jimâ”œÂ®nez, el fotâ”œâ”‚grafo Julio Requejo capturâ”œâ”‚ esta imagen que titulâ”œâ”‚ muy apropiadamente "El Pilar desde casa", pues al fondo se perfilan sus dos torres y el gran cupulâ”œâ”‚n central, y si sale el Pilar, nada mâ”œÃ­s les importa. Por eso, incrustamos un anglosajâ”œâ”‚n "off-topic" para derivar la visual hacia el espacio urbano, el "aire", que fluye hasta la calle Câ”œÃ­diz, pues su tramo entre Laurel y San Diego presenta una inâ”œÂ®dita visiâ”œâ”‚n de las traseras del antiguo Colegio de las Hermanas Recogidas, con el arranque del edificio que alberga su iglesia justo a la izquierda. Este colegio fue fundado en 1594 como "casa para el recogimiento de mujeres perdidas y escandalosas", pues suponâ”œÂ¡an una amenaza mucho grande para el orden pâ”œâ•‘blico y la moral de la Monarquâ”œÂ¡a Hispâ”œÃ­nica, imperial, contrarreformista y ultracatâ”œâ”‚lica. Al menos, en Zaragoza. Tras deambular por diversas ubicaciones, el Virrey Conde de Lemos posibilitâ”œâ”‚ en 1647 su establecimiento aquâ”œÂ¡, en la antigua Morerâ”œÂ¡a, aunque ya sin moros en ella, pues habâ”œÂ¡an sido expulsados en 1610. Con el tiempo, este edificio dejâ”œâ”‚ de tener sentido, y desde 1815 funcionâ”œâ”‚ como mâ”œÃ­s rentable colegio de niâ”œâ–’as, llevado por monjas carmelitas de la Tercera Orden, aunque la impronta conventual llegâ”œâ”‚ a dar nombre a la calle "de las Recogidas", que tras pasar un riego continuaba como "de Veruela", y llegaba hasta el novâ”œÂ¡simo "Salâ”œâ”‚n de Santa Engracia". Al comienzo de la dâ”œÂ®cada de los 70 del pasado siglo XX el colegio era llevado por Carmelitas Misioneras Teresianas, que en 1977 lo vendieron para sacar unas perrillas con que pagarse unas nuevas y lejanas instalaciones en el barrio de Casablanca. En el plazo de un aâ”œâ–’o, fue piqueteado (incluyendo la neoclâ”œÃ­sica iglesia de su interior), para levantar en su solar una pionera y muy necesaria gran superficie comercial. Fuente visual: AHPZ, Archivo Julio Requejo.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16784806103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16784806103.webp', 'https://www.flickr.com/photos/zaragozaantigua/16784806103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21523, 'P.â”¬â•‘ de la Independencia 1926', 'Imagen tomada desde la azotea del nuevo edificio de la Central Telefâ”œâ”‚nica, en el paseo de la Independencia, en un atardecer ya cercano a la noche. A los pies, inmediato, el nuevo edificio de Correos, con sus remates neomudâ”œÂ®jares. Al otro lado de la plaza de Santa Engracia, el palacete del barâ”œâ”‚n de la Rosa, que fuera sede de la Capitanâ”œÂ¡a General entre 1867 y 1888, y casa de Luis Buâ”œâ–’uel entre 1906 y 1917, muy poco antes de ser derribado. Al otro lado del paseo, perspectiva "ruedurivoliense" muy parisina, irrepetible, como el arbolado paseo central, con la farolas reciâ”œÂ®n encendidas. Al fondo, brilla la plaza de la Constituciâ”œâ”‚n, y el telâ”œâ”‚n de fondo de la torre de San Felipe, la câ”œâ•‘pula y torres de Sta. Isabel, El Pilar, un par de palomares, la azucarera del Arrabal, San Gil, la torre y cimborrio de la Seo, y la câ”œâ•‘pula de la central de una entidad de ahorro. Fuente visual: Fundaciâ”œâ”‚n Telefâ”œâ”‚nica', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16834144590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16834144590.webp', 'https://www.flickr.com/photos/zaragozaantigua/16834144590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21559, 'Arco triunfal 1927', 'En su calidad de arquitecto municipal, Miguel â”œÃ¼ngel Navarro repitiâ”œâ”‚ experiencia en materia de celebraciâ”œâ”‚n de triunfos militares durante la dictadura de Primo de Rivera, y dos aâ”œâ–’os despuâ”œÂ®s diseâ”œâ–’â”œâ”‚ otro "arco triunfal" costeado por el Ayuntamiento, esta vez con ocasiâ”œâ”‚n del "homenaje de la victoria y de la fiesta de la raza", en el marco de la colonial "Guerra del Rif" en Marruecos. El desfile fue tambiâ”œÂ®n el 12 de octubre, repitiendo localizaciâ”œâ”‚n en el paseo de la Independencia, a medio camino entre la plaza de Aragâ”œâ”‚n, y la de la Constituciâ”œâ”‚n. Esta vez el diseâ”œâ–’o fue en "estilo â”œÃ­rabe" (sic), si bien adobado con la enseâ”œâ–’a nacional espaâ”œâ–’ola, los escudos de Espaâ”œâ–’a y de Zaragoza, emblemas de todas las armas del ejâ”œÂ®rcito, e inscripciones alusivas a las localidades marroquâ”œÂ¡es de Xauen y Alhucemas. Sobre el arco central, la leyenda "A sus hâ”œÂ®roes, la patria agradecida", en una cara, y "La ciudad inmortal a sus soldados", en la otra. En la imagen, el efâ”œÂ¡mero arco con el lejano fondo de la plaza de Aragâ”œâ”‚n y el monumento al Justiciazgo. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22258876329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22258876329.webp', 'https://www.flickr.com/photos/zaragozaantigua/22258876329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21576, 'P.â”¬â•‘ de la Independencia c.1920', 'Paseo de la Independencia. Al fondo, el Quiosco de la Mâ”œâ•‘sica. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65028300, -0.88272600, '0101000020E61000005186AA984A3FECBF88122D793CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24269505103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24269505103.webp', 'https://www.flickr.com/photos/zaragozaantigua/24269505103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21584, 'P.â”¬â•‘ de la Independencia 1927', 'Imagen de la denominada "Fiesta de la Paz" celebrada el doce de octubre de ese aâ”œâ–’o, con el desfile de tropas de guarniciâ”œâ”‚n de la ciudad, y de repatriados de las campaâ”œâ–’as de Marruecos, bajo el efâ”œÂ¡mero arco triunfal diseâ”œâ–’ado para la ocasiâ”œâ”‚n. El desfile por el arbolado paseo, con vehâ”œÂ¡culos a propulsiâ”œâ”‚n de sangre, va camino de la plaza de Aragâ”œâ”‚n, que queda al fondo. Fuente visual: Miguel Marâ”œÂ¡n Chivite, para ABC.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24604563470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24604563470.webp', 'https://www.flickr.com/photos/zaragozaantigua/24604563470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21604, 'Teatro Variedades 1922', 'Fachada del Teatro Variedades, inaugurado en 1899 en el paseo de la Independencia 24. Es considerado el primer cine estable de la ciudad. En 1934 fue sustituido por el Cine Actualidades, cerrado en 1979. En la imagen, el teatro anuncia el decimonâ”œâ”‚nico texto de Antonio Gil de Zâ”œÃ­rate "Carlos II el Hechizado, drama en tres actos", representado por el cuadro câ”œâ”‚mico-dramâ”œÃ­tico de Emilio Portes, con direcciâ”œâ”‚n de Nicanor Puga.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.65038700, -0.88312300, '0101000020E6100000950D6B2A8B42ECBF2D5F97E13FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27370164186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27370164186.webp', 'https://www.flickr.com/photos/zaragozaantigua/27370164186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21811, 'P.â”¬â•‘ de la Independencia 1930', 'La librerâ”œÂ¡a Fernando Fâ”œÂ® de Madrid, sita en el nâ”œâ•‘mero 15 de la Puerta del Sol, fue fundada en 1840 y era la mâ”œÃ­s câ”œÂ®lebre de la capital. Tras su venta en 1928, se convirtiâ”œâ”‚ en la casa central del servicio de librerâ”œÂ¡a de la Compaâ”œâ–’â”œÂ¡a â”œÃ¬bero Americana de Publicaciones (CIAP). Esta editorial tenâ”œÂ¡a librerâ”œÂ¡as propias repartidas por toda Espaâ”œâ–’a, como la que abriâ”œâ”‚ en 1930 en el paseo de la Independencia 23 y 25 de Zaragoza. La CIAP quebrâ”œâ”‚ en 1931. En la imagen para postal publicitaria, la efâ”œÂ¡mera "Librerâ”œÂ¡a Fâ”œÂ®", en la esquina con la calle de Jerâ”œâ”‚nimo Zurita (izquierda). Fuente visual: www.todocoleccion.net', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65037700, -0.88245900, '0101000020E610000099F221A81A3DECBF0989B48D3FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29974878344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29974878344.webp', 'https://www.flickr.com/photos/zaragozaantigua/29974878344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21855, 'Calle de San Miguel 1934', 'Nebulosa e insâ”œâ”‚lita imagen de la calle de San Miguel capturada a la altura del antiguo nâ”œâ•‘mero 12 y orientada en direcciâ”œâ”‚n a su inicio, al fondo, desde el paseo de la Independencia. A la derecha e inmeditado, el edificio de la central elâ”œÂ®ctrica recayente a las calles de Blancas (la calle que desemboca en primer tâ”œÂ®rmino) y de Porcell. A la izquierda, la fachada del Teatro Circo, esquinero con la calle de Isaac Peral. Al fondo, a la derecha, cartel anunciador del moderno Cine Goya, que confronta con la sede central de ERZ. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65084700, -0.88004200, '0101000020E6100000E46723D74D29ECBF90D959F44ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36065570950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36065570950.webp', 'https://www.flickr.com/photos/zaragozaantigua/36065570950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21858, 'Calle de Joaquâ”œÂ¡n Costa 1931', 'Imagen capturada desde cierta altura y centrada en el arranque de la calle de Joaquâ”œÂ¡n Costa, donde destaca, a punto de ser terminado, el moderno edificio de la Caja de Previsiâ”œâ”‚n Social de Aragâ”œâ”‚n diseâ”œâ–’ado por Regino Borobio, cuyo tamaâ”œâ–’o entonces era adjetivado como "gigantesco". Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64930800, -0.88262700, '0101000020E6100000862172FA7A3EECBFFD8348861CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36126383750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36126383750.webp', 'https://www.flickr.com/photos/zaragozaantigua/36126383750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25597, 'Polâ”œÂ¡gono Romareda 1972', 'Mientras se ultimaban los trabajos de urbanizaciâ”œâ”‚n del novâ”œÂ¡simo Polâ”œÂ¡gono Romareda, y que construyeran el minibloque del Restaurante "Rogelios", que ahora impide ver igual que en la imagen la iglesia de Santa Mâ”œâ”‚nica, las traseras del municipal estadio de fâ”œâ•‘tbol (calle Eduardo Ibarra) fueron provisional lugar de prâ”œÃ­cticas de una autoescuela para aspirantes al carnet de conducir coches... y tractores. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63650200, -0.90367900, '0101000020E61000009D9FE238F0EAECBF57EBC4E578D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850487712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850487712.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850487712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21933, 'Caja de Previsiâ”œâ”‚n Social 1946', 'AHPZ. Archivo Coyne, 1946. "Edificio de la Caja de Previsiâ”œâ”‚n Social de Aragâ”œâ”‚n". Si hasta 1900 la presencia de las Cajas de Ahorro se limitâ”œâ”‚ a la Caja de Ahorros y Monte de Piedad de Zaragoza (1876), en los aâ”œâ–’os siguientes se constituyeron otras: la Caja Obrera de Ahorros y Prâ”œÂ®stamos de la Inmaculada Concepciâ”œâ”‚n (CAI), en 1905, impulsada por la Acciâ”œâ”‚n Social Catâ”œâ”‚lica vinculada al Arzobispado; la Asociaciâ”œâ”‚n de Labradores de Zaragoza (ALZ) creâ”œâ”‚ en 1915 su Caja de Ahorros (transformada en Banco Agrario de Aragâ”œâ”‚n en 1947); y el sindicalismo agrario catâ”œâ”‚lico (Sindicato Central de Aragâ”œâ”‚n de Asociaciones Agrâ”œÂ¡colas Catâ”œâ”‚licas) promoviâ”œâ”‚ en 1918 su propia Caja de Ahorros. En este contexto, el Instituto de Previsiâ”œâ”‚n Social creado en 1921 constituyâ”œâ”‚ su propia Caja, que en lo aâ”œâ–’os treinta llegâ”œâ”‚ a contar con una red de 21 delegaciones y agencias. En la imagen, el edificio central de esta Caja, de 1931 segâ”œâ•‘n diseâ”œâ–’o de Regino y Josâ”œÂ® Borobio en la calle Costa, nâ”¬â•‘ 1, popularmente denominado "Casa de la Perra Gorda" y actual sede de UGT.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64939400, -0.88260700, '0101000020E6100000BF0F0709513EECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15030497922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15030497922.webp', 'https://www.flickr.com/photos/zaragozaantigua/15030497922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22002, 'Cine Dorado 1949', '"Proyecto de reforma del Cine Dorado. Perspectiva". Arquitecto Santiago Lagunas y pintores Fermâ”œÂ¡n Aguayo y Eloy Laguardia. El antiguo edificio del cine Dorâ”œÂ® en el paseo de la Independencia 14 (Teodoro Râ”œÂ¡os, 1914) permaneciâ”œâ”‚ asi entre 1949 y 1967, cuando fue de nuevo reformado. Los tres artistas responsables formaban el Grupo Pâ”œâ”‚rtico. Fuente: www.enciclopedia-aragonesa.com', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65065000, -0.88289900, '0101000020E6100000AF795567B540ECBF3A92CB7F48D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33782848686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33782848686.webp', 'https://www.flickr.com/photos/zaragozaantigua/33782848686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22061, 'P.â”¬â•‘ de la Independencia 1955', 'Archivo Heraldo de Aragâ”œâ”‚n. Gerardo Sancho. 1955. Imagen de arbolado andador central del antiguo paseo de la Independencia. Tras su desmontaje, las farolas de este andador fueron reubicadas unos aâ”œâ–’os despuâ”œÂ®s en el Parque Pignatelli. Los â”œÃ­rboles, no.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65044400, -0.88279000, '0101000020E6100000008C67D0D03FECBF91F0BDBF41D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009124135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009124135.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009124135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
