INSERT INTO public.photos VALUES (22331, 'Paseo Independencia 1965', 'Foto Pomarâ”œâ”‚n, 1965. Imagen de la acera de los impares del paseo de la Independencia de Zaragoza en 1965, desde la plaza de Espaâ”œâ–’a hasta el nâ”œâ•‘mero 29.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18652828506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18652828506.webp', 'https://www.flickr.com/photos/zaragozaantigua/18652828506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22354, 'Paseo Independencia c.1962', 'Foto: Colecciâ”œâ”‚n Sanz San Emeterio. Vista de los edificios de la acera de los pares del paseo de la Independencia de Zaragoza, con la plaza de Espaâ”œâ–’a al fondo. Fuente: rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65089300, -0.88241400, '0101000020E61000009A0AF148BC3CECBF01193A7650D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20681011796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20681011796.webp', 'https://www.flickr.com/photos/zaragozaantigua/20681011796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
