INSERT INTO public.photos VALUES (22401, 'Cine Coliseo 1961', 'Aspecto del estreno de la pelâ”œÂ¡cula Ben-Hur en el cine Coliseo Equitativa, el 3 de enero de 1961. Esta sala, construida en 1949 segâ”œâ•‘n proyecto de Josâ”œÂ® de Yarza y Manuel Martâ”œÂ¡nez, se encontraba en el paseo de la Independencia 19. A la izquierda, bloques de casas aâ”œâ•‘n sin derribar para construir unos grandes almacenes continuando los porches hacia la plaza de Espaâ”œâ–’a. A la derecha, sala de fiestas Capri. Fuente: www.rafaelcastillejo.com', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65083600, -0.88196400, '0101000020E6100000A0FA07910C39ECBF9C8713984ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23583675576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23583675576.webp', 'https://www.flickr.com/photos/zaragozaantigua/23583675576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22406, 'Paseo de la Independencia 1968', 'Imagen de los pilares que sustentan los porches del paseo de la Independencia, como cartelera anunciante del cine que se proyectaba en la ciudad, en esos antiguos y provincianos establecimientos cinematogrâ”œÃ­ficos, a los que se podâ”œÂ¡a ir andando, quâ”œÂ® atraso, luego felizmente sustituidos por otras cosas mâ”œÃ­s modernas, y a varios kilâ”œâ”‚metros de la ciudad. Un "botones" ha sido impactado por el cartel de uno de los filmes publicitados en el paseo, cuando la traducciâ”œâ”‚n de los tâ”œÂ¡tulos (ademâ”œÃ­s del doblaje obligatorio, por Orden Ministerial de 1941) era una implacable y castiza moda impuesta. Asâ”œÂ¡, la gâ”œâ”‚tica "The Black Torment" fue transustanciada en "Horror en la mansiâ”œâ”‚n Fordyke", y en el caso de la pelâ”œÂ¡cula de Arthur Penn, "Bonnie & Clyde" se quedâ”œâ”‚ en el cacofâ”œâ”‚nico "Bonnie y Clyde", que clarifica significativamente el tâ”œÂ¡tulo. Era una de las cosas buenas de aquellos tiempos: todo el mundo hablaba espaâ”œâ–’ol, aunque en ocasiones resultara mâ”œÃ­s de Churubusco, que de Valladolid. Mas quienes tuvieron que desplazarse, por vocaciâ”œâ”‚n, o necesidad, pronto descubrieron, allâ”œÃ­ afuera, una realidad mâ”œÃ­s plural y compleja. Quâ”œÂ® recuerdos. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65077200, -0.88269400, '0101000020E61000007903CC7C073FECBF8693347F4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24476390801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24476390801.webp', 'https://www.flickr.com/photos/zaragozaantigua/24476390801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22445, 'Cineastas 1965', 'Interesante orla de la "primera promociâ”œâ”‚n de la Escuela Cesaraugustana de directores cinematogrâ”œÃ­ficos, 1965". Como decano figura el excelentâ”œÂ¡simo Luis Buâ”œâ–’uel, flanqueado por los catedrâ”œÃ­ticos Serguâ”œÂ®i Eisenstein y Charles Chaplin, ademâ”œÃ­s de una interesante nâ”œâ”‚mina de cualificados profesores europeos y norteamericanos del ramo audiovisual. Los alumnos de esta hornada conforman un excelente muestrario del cine independiente y amateur que, con toda la dignidad del mundo, se podâ”œÂ¡a llegar a hacer en la ciudad en esos aâ”œâ–’os. Entre ellos se encuentra Josâ”œÂ® Luis Pomarâ”œâ”‚n, en cuyo estudio profesional del paseo de la Independencia nâ”¬â•‘ 30 se realizâ”œâ”‚ esta iluminada obra. Fuente: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64984500, -0.88379700, '0101000020E610000075B169A51048ECBF0C3CF71E2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30985898885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30985898885.webp', 'https://www.flickr.com/photos/zaragozaantigua/30985898885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22537, 'Paseo Independencia 1972', 'Un tranvâ”œÂ¡a de la lâ”œÂ¡nea 11 parque-San Josâ”œÂ® atraviesa el paseo de la Independencia. Tambiâ”œÂ®n aparece un caracterâ”œÂ¡stico taxi de la â”œÂ®poca. Al fondo, la plaza de Espaâ”œâ–’a. Fuente visual: www.flickr.com/photos/jhm0284/5813094884/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65082100, -0.88234700, '0101000020E6100000A62897C62F3CECBF67463F1A4ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864455426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864455426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864455426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22591, 'Calle Câ”œÃ­diz 1978', 'J.L.O.G. Febrero 1978. Imagen de la calle de Câ”œÃ­diz cuando se estaba procediendo al derribo del antiguo convento de las "Recogidas" (Nâ”¬Â¬ Sâ”¬Â¬ de la Misericordia de las Hermanas Recogidas), gestionado en su â”œâ•‘ltima etapa (1971-1977) por Carmelitas Misioneras Teresianas, cuando fue vendido a la familia Parra. En este solar se levantarâ”œÂ¡a, despuâ”œÂ®s, el centro comercial "El Caracol", y las monjas se fueron a unas nuevas y lejanas instalaciones en el barrio de Casablanca. La fachada del convento llegaba hasta la plaza del Carmen, y llevaba casi un siglo albergando un colegio de niâ”œâ–’as. Fuente: www.facebook.com/photo.php?fbid=725221827572843&set=g...', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15772023001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15772023001.webp', 'https://www.flickr.com/photos/zaragozaantigua/15772023001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22609, 'Recogidas Calle Câ”œÃ­diz 1978', 'La calle Câ”œÃ­diz en el inicio del derribo del antiguo convento de las "Recogidas" (denominaciâ”œâ”‚n abreviada de "Nâ”¬Â¬ Sâ”¬Â¬ de la Misericordia de las Hermanas Recogidas"), gestionado en su â”œâ•‘ltima etapa (1971-1977) por las MM. Carmelitas Misioneras Teresianas, hasta que vendieron la propiedad del suelo a un promotor inmobiliario local, y protagonizaron un nuevo capâ”œÂ¡tulo de la "Operaciâ”œâ”‚n conventos y colegios privados", adquiriendo a cambio solares en vâ”œÂ¡rgenes y lejanas instalaciones en el barrio de Casablanca. En este solar, tras el derribo de lo que hubiera o hubiese, râ”œÃ­pidamente, serâ”œÃ­ construida una gran superficie comercial de lento nombre y notable popularidad, luego decreciente. Tras deambular por diversas ubicaciones de la ciudad, el Virrey Conde de Lemos habâ”œÂ¡a posibilitado en 1647 el establecimiento en la antigua Morerâ”œÂ¡a, mâ”œÃ­s despejada desde la expulsiâ”œâ”‚n de los moriscos en 1610, del Convento de las Recogidas de las MM. Carmelitas Terciarias Claustrales, con iglesia propia, como beaterio o "casa para el recogimiento de mujeres perdidas y escandalosas" (ergo mujeres prostituidas) sin votos, y estancia temporal. La entonces calle de Monzâ”œâ”‚n serâ”œÃ­ denominada, por ello, Ã”Ã‡Â£de las RecogidasÃ”Ã‡Ã˜. A finales del XVIII el convento fue reedificado en formas barroco-clasicistas, o neoclâ”œÃ­sicas. En 1868 se instalâ”œâ”‚ aquâ”œÂ¡ un colegio de niâ”œâ–’as, y en 1869 el Ayuntamiento proyectâ”œâ”‚ reformar la calle, entonces denominada del Parque, lo que supuso el derribo de sus fachadas, y la construcciâ”œâ”‚n de unas nuevas diseâ”œâ–’adas por Fernando de Yarza, recayentes ya a la nueva calle Câ”œÃ­diz, y a la plaza del Carmen. En 1964, las monjas alquilaron la parte que daba a esta plaza para el establecimiento de varias tiendas. En la imagen, perspectiva del antiguo convento, con la plaza del Carmen al fondo, precisamente por donde habâ”œÂ¡a comenzado el derribo. El edificio de la iglesia estaba mâ”œÃ­s prâ”œâ”‚ximo a esta plaza, y ya ha sido desmochado de su espadaâ”œâ–’a y cubierta.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19117945473.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19117945473.webp', 'https://www.flickr.com/photos/zaragozaantigua/19117945473/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22685, 'P.â”¬â•‘ de la Independencia 1970', 'Interesante, colorista, e insâ”œâ”‚lita imagen parcial del paseo de la Independencia, con visual del cartel anunciador del Teatro Argensola, que naciera como "Parisiana", pero que en 1938 fue "nacionalizado" en su denominaciâ”œâ”‚n, segâ”œâ•‘n la polâ”œÂ¡tica nacionalista del momento. Esquinero con la calle de Zurita, a la izquierda, vio clausurada su vida artâ”œÂ¡stica en la prodigiosa dâ”œÂ®cada de los 80, y convertido en otro necesario pasaje comercial al uso. Por delante del teatro transita la composiciâ”œâ”‚n 82+151 de la tranviaria lâ”œÂ¡nea 5 (Venecia-Delicias) traqueteando hacia la plaza de Huesca. Tras la clausura de la lâ”œÂ¡nea, a finales del aâ”œâ–’o siguiente, la unidad 82 fue instalada en 1974 en el Cabezo de Buenavista como biblioteca pâ”œâ•‘blica infantil, hasta terminar en el desguace, en 1980. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œÂ¡a de junio de 1970, en su paso por la ciudad durante su viaje a Europa de ese aâ”œâ–’o. Fuente visual: www.flickr.com/photos/intervene/1994927371/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65033400, -0.88246700, '0101000020E61000004F93196F2B3DECBF0ABDFE243ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26740874514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26740874514.webp', 'https://www.flickr.com/photos/zaragozaantigua/26740874514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22723, 'P.â”¬â•‘ de la Independencia 1970', 'Imagen de la unidad 53 de los trolebuses urbanos, de la lâ”œÂ¡nea "Ciudad Jardâ”œÂ¡n", en el paseo de la Independencia, a punto de llegar a la terminal situada en la plaza de Santa Engracia. Se trata de uno de los BUT de dos pisos que llegaron de Londres la dâ”œÂ®cada anterior. A su derecha, la unidad 105 de la tranviaria lâ”œÂ¡nea "Venecia-Delicias", en direcciâ”œâ”‚n a la plaza de Huesca. De telâ”œâ”‚n de fondo, el edificio de Correos y Telâ”œÂ®grafos, y a su lado, el de los Telâ”œÂ®fonos. A la derecha, mâ”œÂ¡nima visual de la cobertura de caâ”œâ–’izo tras la que se estaba construyendo el gigante y nuevo nâ”¬â•‘ 1 de la plaza de Aragâ”œâ”‚n, donde estuviera ubicado el antiguo hotelito sede del Gobierno Civil. Fuente visual: Foto John Scragg, a travâ”œÂ®s de www.forotrenes.com/', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64951900, -0.88354300, '0101000020E6100000E48233F8FB45ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30390389653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30390389653.webp', 'https://www.flickr.com/photos/zaragozaantigua/30390389653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22736, 'Pâ”¬â•‘ Independencia 1972', 'Imagen capturada en el paseo de la Independencia, con vista parcial del tramo entre la calle de Câ”œÃ­diz, a la derecha, fuera de plano, y el nâ”¬â•‘ 24, y centrada en moderno nâ”¬â•‘ 22 del paseo-autopista, uno de esos especâ”œÂ¡menes recrecidos y acristalados que empezaban a marcar tendencia edilicia como sâ”œÂ¡mbolo de los nuevos tiempos La reiteraciâ”œâ”‚n de letras y pegatinas sobre los cristales, sâ”œÂ¡ntoma de reciente colocaciâ”œâ”‚n. A su derecha, el bloque del nâ”¬â•‘ 18-20, en el estilo neorregionalista de los 40''s; a su izquierda, una reliquia de los tiempos de la antigua calle de la Independencia, cuando alguien soâ”œâ–’â”œâ”‚ en voz alta que esto era la rue de Rivoli zaragozana. Unos aâ”œâ–’os despuâ”œÂ®s este edificio serâ”œÂ¡a remodelado durante las obras de habilitaciâ”œâ”‚n de una gran superficie comercial con forma de caracol. Fuente visual: foto Estudio Coyne, AHPZ.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65038700, -0.88312300, '0101000020E6100000950D6B2A8B42ECBF2D5F97E13FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31324849320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31324849320.webp', 'https://www.flickr.com/photos/zaragozaantigua/31324849320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
